1	/**
2	 * Connections tRPC sub-router.
3	 *
4	 * All procedures use serviceProcedure (JWT auth required).
5	 * orgId comes as an input parameter (no tenant middleware in tRPC).
6	 *
7	 * `disconnect` fires the "platform/connection.lifecycle" Inngest event
8	 * to trigger the connection teardown workflow.
9	 */
10	import { db } from "@db/app/client";
11	import {
12	  gatewayBackfillRuns,
13	  gatewayInstallations,
14	  gatewayLifecycleLogs,
15	} from "@db/app/schema";
16	import type { ProviderDefinition } from "@repo/app-providers";
17	import { getProvider, sourceTypeSchema } from "@repo/app-providers";
18	import {
19	  BACKFILL_TERMINAL_STATUSES,
20	  backfillRunRecord,
21	} from "@repo/app-providers/contracts";
22	import type { TRPCRouterRecord } from "@trpc/server";
23	import { TRPCError } from "@trpc/server";
24	import { and, eq } from "@vendor/db";
25	import { log } from "@vendor/observability/log/next";
26	import { z } from "zod";
27	import { inngest } from "../../inngest/client";
28	import { buildAuthorizeUrl } from "../../lib/oauth/authorize";
29	import { providerConfigs } from "../../lib/provider-configs";
30	import { getActiveTokenForInstallation } from "../../lib/token-helpers";
31	import { serviceProcedure } from "../../trpc";
32	
33	// ── Connections Router ──────────────────────────────────────────────────────
34	
35	export const connectionsRouter = {
36	  /**
37	   * List installations, optionally filtered by status.
38	   * Source: GET /connections
39	   */
40	  list: serviceProcedure
41	    .input(
42	      z.object({
43	        orgId: z.string(),
44	        status: z.string().optional(),
45	      })
46	    )
47	    .query(async ({ input }) => {
48	      const conditions = [eq(gatewayInstallations.orgId, input.orgId)];
49	      if (input.status) {
50	        conditions.push(eq(gatewayInstallations.status, input.status));
51	      }
52	
53	      const rows = await db
54	        .select({
55	          id: gatewayInstallations.id,
56	          provider: gatewayInstallations.provider,
57	          externalId: gatewayInstallations.externalId,
58	          orgId: gatewayInstallations.orgId,
59	          status: gatewayInstallations.status,
60	        })
61	        .from(gatewayInstallations)
62	        .where(and(...conditions));
63	
64	      return rows;
65	    }),
66	
67	  /**
68	   * Token vault -- returns decrypted provider token for a connection.
69	   * Source: GET /connections/:id/token
70	   */
71	  getToken: serviceProcedure
72	    .input(
73	      z.object({
74	        id: z.string(),
75	      })
76	    )
77	    .query(async ({ input }) => {
78	      const installationRows = await db
79	        .select()
80	        .from(gatewayInstallations)
81	        .where(eq(gatewayInstallations.id, input.id))
82	        .limit(1);
83	
84	      const installation = installationRows[0];
85	
86	      if (!installation) {
87	        throw new TRPCError({
88	          code: "NOT_FOUND",
89	          message: "Connection not found",
90	        });
91	      }
92	
93	      if (installation.status !== "active") {
94	        throw new TRPCError({
95	          code: "BAD_REQUEST",
96	          message: `Installation not active (status: ${installation.status})`,
97	        });
98	      }
99	
100	      const providerName = installation.provider;
101	      const config = providerConfigs[providerName];
102	
103	      try {
104	        const providerDef = getProvider(providerName);
105	
106	        // SAFETY: getProvider() returns the full generic ProviderDefinition<TConfig, ...>
107	        // but the helper takes the base ProviderDefinition. The generic parameters are
108	        // erased at runtime -- the cast is safe because the concrete type is a supertype.
109	        const { token, expiresAt } = await getActiveTokenForInstallation(
110	          installation,
111	          config,
112	          providerDef as ProviderDefinition
113	        );
114	
115	        return {
116	          accessToken: token,
117	          provider: providerName,
118	          expiresIn: expiresAt
119	            ? Math.floor((new Date(expiresAt).getTime() - Date.now()) / 1000)
120	            : 3600, // GitHub installation tokens expire in 1 hour
121	        };
122	      } catch (err) {
123	        const message = err instanceof Error ? err.message : "unknown";
124	        log.warn("[connections] token retrieval failed", {
125	          installationId: input.id,
126	          provider: providerName,
127	          error: message,
128	        });
129	
130	        if (message === "no_token_found") {
131	          throw new TRPCError({
132	            code: "NOT_FOUND",
133	            message: "no_token_found",
134	          });
135	        }
136	        if (
137	          message === "token_expired" ||
138	          message === "token_expired:no_refresh_token"
139	        ) {
140	          throw new TRPCError({
141	            code: "BAD_REQUEST",
142	            message,
143	          });
144	        }
145	        throw new TRPCError({
146	          code: "INTERNAL_SERVER_ERROR",
147	          message: `token_generation_failed: ${message}`,
148	        });
149	      }
150	    }),
151	
152	  /**
153	   * Disconnect (teardown) a connection.
154	   *
155	   * Fires "platform/connection.lifecycle" Inngest event to initiate teardown.
156	   */
157	  disconnect: serviceProcedure
158	    .input(
159	      z.object({
160	        id: z.string(),
161	        provider: sourceTypeSchema,
162	      })
163	    )
164	    .mutation(async ({ input }) => {
165	      const installationRows = await db
166	        .select()
167	        .from(gatewayInstallations)
168	        .where(
169	          and(
170	            eq(gatewayInstallations.id, input.id),
171	            eq(gatewayInstallations.provider, input.provider)
172	          )
173	        )
174	        .limit(1);
175	
176	      const installation = installationRows[0];
177	
178	      if (!installation) {
179	        throw new TRPCError({
180	          code: "NOT_FOUND",
181	          message: "Connection not found",
182	        });
183	      }
184	
185	      // Audit log: capture user-initiated disconnect intent before event fires
186	      await db.insert(gatewayLifecycleLogs).values({
187	        installationId: input.id,
188	        event: "user_disconnect",
189	        fromStatus: installation.status,
190	        toStatus: "revoked",
191	        reason: "User-initiated disconnect via platform service",
192	        metadata: {
193	          source: "platform_disconnect_handler",
194	          triggeredBy: "user",
195	        },
196	      });
197	
198	      // Fire Inngest event to trigger connection teardown workflow
199	      await inngest.send({
200	        name: "platform/connection.lifecycle",
201	        data: {
202	          reason: "user_disconnect",
203	          installationId: input.id,
204	          orgId: installation.orgId,
205	          provider: input.provider,
206	          triggeredBy: "user" as const,
207	        },
208	      });
209	
210	      return { status: "teardown_initiated", installationId: input.id };
211	    }),
212	
213	  /**
214	   * Build OAuth authorize URL for a provider.
215	   * Source: GET /connections/:provider/authorize
216	   */
217	  getAuthorizeUrl: serviceProcedure
218	    .input(
219	      z.object({
220	        provider: sourceTypeSchema,
221	        orgId: z.string(),
222	        connectedBy: z.string(),
223	        redirectTo: z.string().optional(),
224	      })
225	    )
226	    .query(async ({ input }) => {
227	      const result = await buildAuthorizeUrl({
228	        provider: input.provider,
229	        orgId: input.orgId,
230	        connectedBy: input.connectedBy,
231	        redirectTo: input.redirectTo,
232	      });
233	
234	      if (!result.ok) {
235	        throw new TRPCError({
236	          code: "BAD_REQUEST",
237	          message: result.error,
238	        });
239	      }
240	
241	      return { url: result.url, state: result.state };
242	    }),
243	
244	  /**
245	   * List backfill runs for a connection.
246	   * Source: GET /connections/:id/backfill-runs
247	   */
248	  listBackfillRuns: serviceProcedure
249	    .input(
250	      z.object({
251	        installationId: z.string(),
252	        status: z.string().optional(),
253	      })
254	    )
255	    .query(async ({ input }) => {
256	      const conditions = [
257	        eq(gatewayBackfillRuns.installationId, input.installationId),
258	      ];
259	      if (input.status) {
260	        conditions.push(eq(gatewayBackfillRuns.status, input.status));
261	      }
262	
263	      const runs = await db
264	        .select({
265	          entityType: gatewayBackfillRuns.entityType,
266	          providerResourceId: gatewayBackfillRuns.providerResourceId,
267	          since: gatewayBackfillRuns.since,
268	          depth: gatewayBackfillRuns.depth,
269	          status: gatewayBackfillRuns.status,
270	          pagesProcessed: gatewayBackfillRuns.pagesProcessed,
271	          eventsProduced: gatewayBackfillRuns.eventsProduced,
272	          eventsDispatched: gatewayBackfillRuns.eventsDispatched,
273	          completedAt: gatewayBackfillRuns.completedAt,
274	        })
275	        .from(gatewayBackfillRuns)
276	        .where(and(...conditions));
277	
278	      return runs;
279	    }),
280	
281	  /**
282	   * Upsert a backfill run record.
283	   * Source: POST /connections/:id/backfill-runs
284	   */
285	  upsertBackfillRun: serviceProcedure
286	    .input(
287	      z.object({
288	        installationId: z.string(),
289	        run: backfillRunRecord,
290	      })
291	    )
292	    .mutation(async ({ input }) => {
293	      const now = new Date().toISOString();
294	      const data = input.run;
295	      const isTerminal = (
296	        BACKFILL_TERMINAL_STATUSES as readonly string[]
297	      ).includes(data.status);
298	
299	      const sharedFields = {
300	        since: data.since,
301	        depth: data.depth,
302	        status: data.status,
303	        pagesProcessed: data.pagesProcessed,
304	        eventsProduced: data.eventsProduced,
305	        eventsDispatched: data.eventsDispatched,
306	        error: data.error ?? null,
307	        completedAt: isTerminal ? now : null,
308	        updatedAt: now,
309	      };
310	
311	      await db
312	        .insert(gatewayBackfillRuns)
313	        .values({
314	          installationId: input.installationId,
315	          entityType: data.entityType,
316	          providerResourceId: data.providerResourceId,
317	          ...sharedFields,
318	          startedAt: data.status === "running" ? now : null,
319	        })
320	        .onConflictDoUpdate({
321	          target: [
322	            gatewayBackfillRuns.installationId,
323	            gatewayBackfillRuns.providerResourceId,
324	            gatewayBackfillRuns.entityType,
325	          ],
326	          set: sharedFields,
327	        });
328	
329	      return { status: "ok" as const };
330	    }),
331	} satisfies TRPCRouterRecord;
