  preTransformVercelWebhookPayloadSchema,
  vercelWebhookEventTypeSchema,
  vercelWebhookPayloadSchema,
} from "./providers/vercel/schemas";
export { transformVercelDeployment } from "./providers/vercel/transformers";
// ── Registry ─────────────────────────────────────────────────────────────────
export type {
  AccountInfoFor,
  AnyEndpointKey,
  AuthDefFor,
  EndpointKey,
  EndpointKeysFor,
  EventKey,
  EventKeysFor,
  EventRegistryEntry,
  HasBuildAuth,
  PathParamsFor,
  ProviderAccountInfo,
  ProviderConfig,
  ProviderKey,
  ProviderName,
  ProviderShape,
  ResponseDataFor,
  SourceType,
} from "./registry";
export {
  EVENT_REGISTRY,
  eventKeySchema,
  eventRegistryEntrySchema,
  getDefaultSyncEvents,
  getProvider,
  PROVIDER_ENVS,
  PROVIDERS,
  providerAccountInfoSchema,
  providerConfigSchema,
  sourceTypeSchema,
} from "./registry";
export {
  computeHmac,
  sha256Hex,
  timingSafeEqual,
  timingSafeStringEqual,
} from "./runtime/crypto";
export { transformWebhookPayload } from "./runtime/dispatch";
export { deriveObservationType, getBaseEventType } from "./runtime/event-norm";
export { createRS256JWT } from "./runtime/jwt";
export {
  encodeHtmlEntities,
  sanitizeBody,
  sanitizeContent,
  sanitizeTitle,
  truncateWithEllipsis,
} from "./runtime/sanitize";
export {
  logValidationErrors,
  sanitizePostTransformEvent,
  validatePostTransformEvent,
} from "./runtime/validation";
// ── Runtime Utilities ─────────────────────────────────────────────────────────
export { deriveVerifySignature } from "./runtime/verify/index";

import { Icons } from "@repo/ui/components/icons";
import { TeamNameForm } from "./_components/team-name-form";

export const dynamic = "force-dynamic";

export default function CreateTeamPage() {
  return (
    <div className="flex flex-1 items-center justify-center px-4 pb-32">
      <div className="w-full max-w-md space-y-4">
        {/* Logo */}
        <div className="w-fit rounded-sm bg-card p-3">
          <Icons.logoShort className="h-5 w-5 text-foreground" />
        </div>

        <div className="space-y-4">
          <h1 className="pb-4 font-medium font-pp text-2xl text-foreground">
            Create your team
          </h1>
          <TeamNameForm />
        </div>
      </div>
    </div>
  );
}

