1	import { gatewayInstallations, orgIntegrations } from "@db/app/schema";
2	import {
3	  getDefaultSyncEvents,
4	  getProvider,
5	  gwInstallationBackfillConfigSchema,
6	  type NormalizedInstallation,
7	  type ProviderName,
8	  type ResourcePickerExecuteApiFn,
9	  sourceTypeSchema,
10	} from "@repo/app-providers";
11	import type { SourceIdentifier } from "@repo/app-validation";
12	import { createPlatformCaller } from "@repo/platform-trpc/caller";
13	import type { TRPCRouterRecord } from "@trpc/server";
14	import { TRPCError } from "@trpc/server";
15	import { parseError } from "@vendor/observability/error/next";
16	import { log } from "@vendor/observability/log/next";
17	import { and, eq } from "drizzle-orm";
18	import yaml from "yaml";
19	import { z } from "zod";
20	import { orgScopedProcedure } from "../../trpc";
21	
22	/**
23	 * Connections Router
24	 *
25	 * Manages org-level OAuth connections (GitHub, Vercel, Linear, etc.)
26	 * Queries gw_installations directly (org-scoped).
27	 *
28	 * Proxies to memory service tRPC for token vault, OAuth, and API operations.
29	 *
30	 * Table: gatewayInstallations (lightfast_gateway_installations)
31	 * Scope: Org-scoped (active org required)
32	 */
33	
34	export const connectionsRouter = {
35	  /**
36	   * Get OAuth authorize URL from the memory service.
37	   *
38	   * Proxies the memory service authorize endpoint since browsers
39	   * can't set custom headers (X-Org-Id) during popup navigation.
40	   */
41	  getAuthorizeUrl: orgScopedProcedure
42	    .input(
43	      z.object({
44	        provider: sourceTypeSchema,
45	      })
46	    )
47	    .query(async ({ ctx, input }) => {
48	      const platform = await createPlatformCaller();
49	      return platform.connections.getAuthorizeUrl({
50	        provider: input.provider,
51	        orgId: ctx.auth.orgId,
52	        connectedBy: ctx.auth.userId,
53	      });
54	    }),
55	
56	  /**
57	   * List org's OAuth integrations (all providers)
58	   *
59	   * Returns all active OAuth integrations connected by the org.
60	   */
61	  list: orgScopedProcedure.query(async ({ ctx }) => {
62	    const installations = await ctx.db
63	      .select()
64	      .from(gatewayInstallations)
65	      .where(
66	        and(
67	          eq(gatewayInstallations.orgId, ctx.auth.orgId),
68	          eq(gatewayInstallations.status, "active")
69	        )
70	      );
71	
72	    return installations.map((inst) => ({
73	      id: inst.id,
74	      sourceType: inst.provider,
75	      isActive: true,
76	      connectedAt: inst.createdAt,
77	      lastSyncAt: inst.updatedAt,
78	    }));
79	  }),
80	
81	  /**
82	   * Disconnect an integration.
83	   *
84	   * Delegates to the memory service which triggers the durable
85	   * connection-teardown workflow (gate-first: closes ingress immediately).
86	   */
87	  disconnect: orgScopedProcedure
88	    .input(
89	      z.object({
90	        integrationId: z.string(),
91	      })
92	    )
93	    .mutation(async ({ ctx, input }) => {
94	      // Fetch installation to get provider (required for disconnect)
95	      // and enforce org scoping before calling the memory service
96	      const rows = await ctx.db
97	        .select({
98	          id: gatewayInstallations.id,
99	          provider: gatewayInstallations.provider,
100	        })
101	        .from(gatewayInstallations)
102	        .where(
103	          and(
104	            eq(gatewayInstallations.id, input.integrationId),
105	            eq(gatewayInstallations.orgId, ctx.auth.orgId)
106	          )
107	        )
108	        .limit(1);
109	
110	      const installation = rows[0];
111	      if (!installation) {
112	        throw new TRPCError({
113	          code: "NOT_FOUND",
114	          message: "Integration not found or access denied",
115	        });
116	      }
117	
118	      const platform = await createPlatformCaller();
119	      await platform.connections.disconnect({
120	        id: installation.id,
121	        provider: installation.provider,
122	      });
123	
124	      // Cascade: mark all org integrations for this installation as disconnected.
125	      // This covers all providers (Vercel, Linear, Sentry, Apollo, GitHub).
126	      // The cascade here ensures the gate closes immediately on user-triggered disconnect.
127	      const now = new Date().toISOString();
128	      await ctx.db
129	        .update(orgIntegrations)
130	        .set({
131	          status: "disconnected",
132	          statusReason: "installation_revoked",
133	          updatedAt: now,
134	        })
135	        .where(eq(orgIntegrations.installationId, input.integrationId));
136	
137	      return { success: true };
138	    }),
139	
140	  /**
141	   * Update backfill configuration for a gateway installation.
142	   *
143	   * Stores depth + entityTypes on gatewayInstallations.backfillConfig.
144	   * Used by SourceSettingsForm and as defaults for notifyBackfill().
145	   */
146	  updateBackfillConfig: orgScopedProcedure
147	    .input(
148	      z.object({
149	        installationId: z.string().min(1),
150	        backfillConfig: gwInstallationBackfillConfigSchema,
151	      })
152	    )
153	    .mutation(async ({ ctx, input }) => {
154	      const result = await ctx.db
155	        .update(gatewayInstallations)
156	        .set({ backfillConfig: input.backfillConfig })
157	        .where(
158	          and(
159	            eq(gatewayInstallations.id, input.installationId),
160	            eq(gatewayInstallations.orgId, ctx.auth.orgId)
161	          )
162	        )
163	        .returning({ id: gatewayInstallations.id });
164	
165	      if (!result[0]) {
166	        throw new TRPCError({
167	          code: "NOT_FOUND",
168	          message: "Installation not found or access denied",
169	        });
170	      }
171	
172	      return { success: true };
173	    }),
174	
175	  /**
176	   * GitHub-specific operations
177	   */
178	  github: {
179	    /**
180	     * Validate and refresh installations from GitHub API
181	     *
182	     * Re-fetches installations from GitHub using stored access token
183	     * and updates the installation's providerAccountInfo.
184	     *
185	     * Returns counts of added/removed installations.
186	     */
187	    validate: orgScopedProcedure.mutation(async ({ ctx }) => {
188	      const result = await ctx.db
189	        .select()
190	        .from(gatewayInstallations)
191	        .where(
192	          and(
193	            eq(gatewayInstallations.orgId, ctx.auth.orgId),
194	            eq(gatewayInstallations.provider, "github"),
195	            eq(gatewayInstallations.status, "active")
196	          )
197	        )
198	        .limit(1);
199	
200	      const installation = result[0];
201	
202	      if (!installation) {
203	        throw new TRPCError({
204	          code: "NOT_FOUND",
205	          message: "GitHub integration not found. Please connect GitHub first.",
206	        });
207	      }
208	
209	      const providerAccountInfo = installation.providerAccountInfo;
210	      if (providerAccountInfo?.sourceType !== "github") {
211	        throw new TRPCError({
212	          code: "INTERNAL_SERVER_ERROR",
213	          message: "Invalid provider data type",
214	        });
215	      }
216	
217	      try {
218	        const platform = await createPlatformCaller();
219	
220	        // Validate that the installation still exists on GitHub (App JWT auth via proxy)
221	        const result = await platform.proxy.execute({
222	          installationId: installation.id,
223	          endpointId: "get-app-installation",
224	          pathParams: { installation_id: installation.externalId },
225	        });
226	
227	        if (result.status !== 200) {
228	          throw new Error(
229	            `GitHub installation not found: status ${result.status}`
230	          );
231	        }
232	
233	        // Update only lastValidatedAt — display data is resolved live, not cached
234	        const existingInfo = installation.providerAccountInfo;
235	        const now = new Date().toISOString();
236	        if (existingInfo?.sourceType === "github") {
237	          await ctx.db
238	            .update(gatewayInstallations)
239	            .set({
240	              providerAccountInfo: { ...existingInfo, lastValidatedAt: now },
241	              updatedAt: now,
242	            })
243	            .where(eq(gatewayInstallations.id, installation.id));
244	        }
245	
246	        return { added: 0, removed: 0, total: 1 };
247	      } catch (error: unknown) {
248	        log.error("[connections/github] validate failed", {
249	          clerkOrgId: ctx.auth.orgId,
250	          error: parseError(error),
251	        });
252	
253	        throw new TRPCError({
254	          code: "INTERNAL_SERVER_ERROR",
255	          message: "Failed to validate GitHub installation",
256	          cause: error,
257	        });
258	      }
259	    }),
260	
261	    /**
262	     * Detect repository configuration (lightfast.yml)
263	     *
264	     * Checks if the repository contains a lightfast.yml configuration file
265	     * and returns its content if found.
266	     */
267	    detectConfig: orgScopedProcedure
268	      .input(
269	        z.object({
270	          integrationId: z.string(), // gatewayInstallations.id
271	          installationId: z.string(), // GitHub App installation external ID
272	          fullName: z.string(), // "owner/repo"
273	          ref: z.string().optional(), // branch/tag/sha (defaults to default branch)
274	        })
275	      )
276	      .query(async ({ ctx, input }) => {
277	        // Verify org owns this installation
278	        const result = await ctx.db
279	          .select()
280	          .from(gatewayInstallations)
281	          .where(
282	            and(
283	              eq(gatewayInstallations.id, input.integrationId),
284	              eq(gatewayInstallations.orgId, ctx.auth.orgId)
285	            )
286	          )
287	          .limit(1);
288	
289	        const installation = result[0];
290	
291	        if (!installation) {
292	          throw new TRPCError({
293	            code: "NOT_FOUND",
294	            message: "Installation not found or access denied",
295	          });
296	        }
297	
298	        // Verify the GitHub App installation is accessible via the table column
299	        if (installation.externalId !== input.installationId) {
300	          throw new TRPCError({
301	            code: "NOT_FOUND",
302	            message:
303	              "Installation not found or not accessible to this connection",
304	          });
305	        }
306	
307	        const [owner, repo] = input.fullName.split("/");
308	        if (!(owner && repo)) {
309	          throw new TRPCError({
310	            code: "BAD_REQUEST",
311	            message: "Invalid repository name format. Expected 'owner/repo'",
312	          });
313	        }
314	
315	        try {
316	          const platform = await createPlatformCaller();
317	
318	          let ref = input.ref;
319	          if (!ref) {
320	            const repoResult = await platform.proxy.execute({
321	              installationId: input.integrationId,
322	              endpointId: "get-repo",
323	              pathParams: { owner, repo },
324	            });
325	            if (repoResult.status !== 200) {
326	              throw new TRPCError({
327	                code: "INTERNAL_SERVER_ERROR",
328	                message: "Failed to fetch repository info from GitHub",
329	              });
330	            }
331	            ref = (repoResult.data as { default_branch: string })
332	              .default_branch;
333	          }
334	
335	          if (ref && !/^[a-zA-Z0-9._/-]+$/.test(ref)) {
336	            throw new TRPCError({
337	              code: "BAD_REQUEST",
338	              message:
339	                "Invalid ref format. Only alphanumeric characters, dots, dashes, slashes, and underscores are allowed.",
340	            });
341	          }
342	
343	          const candidates = [
344	            "lightfast.yml",
345	            ".lightfast.yml",
346	            "lightfast.yaml",
347	            ".lightfast.yaml",
348	          ];
349	
350	          for (const path of candidates) {
351	            const queryParams: Record<string, string> = {};
352	            if (ref) {
353	              queryParams.ref = ref;
354	            }
355	            const fileResult = await platform.proxy.execute({
356	              installationId: input.integrationId,
357	              endpointId: "get-file-contents",
358	              pathParams: { owner, repo, path },
359	              queryParams,
360	            });
361	
362	            if (fileResult.status === 404) {
363	              continue;
364	            }
365	
366	            if (fileResult.status !== 200) {
367	              throw new TRPCError({
368	                code: "INTERNAL_SERVER_ERROR",
369	                message: "Failed to fetch file contents from GitHub",
370	              });
371	            }
372	
373	            const data = fileResult.data as {
374	              content?: string;
375	              type?: string;
376	              size?: number;
377	              sha?: string;
378	            };
379	
380	            if (
381	              !Array.isArray(data) &&
382	              data.content !== undefined &&
383	              data.type !== undefined
384	            ) {
385	              const maxSize = 50 * 1024;
386	              if (typeof data.size === "number" && data.size > maxSize) {
387	                throw new TRPCError({
388	                  code: "BAD_REQUEST",
389	                  message: `Config file too large. Maximum size is ${maxSize / 1024}KB.`,
390	                });
391	              }
392	
393	              const content = Buffer.from(data.content, "base64").toString(
394	                "utf-8"
395	              );
396	
397	              try {
398	                yaml.parse(content);
399	              } catch {
400	                throw new TRPCError({
401	                  code: "BAD_REQUEST",
402	                  message: "Invalid YAML format in config file.",
403	                });
404	              }
405	
406	              return {
407	                exists: true,
408	                path,
409	                content,
410	                sha: data.sha ?? "",
411	              };
412	            }
413	          }
414	
415	          return { exists: false };
416	        } catch (error: unknown) {
417	          log.error("[connections/github] detectConfig failed", {
418	            clerkOrgId: ctx.auth.orgId,
419	            error: parseError(error),
420	          });
421	
422	          throw new TRPCError({
423	            code: "INTERNAL_SERVER_ERROR",
424	            message: "Failed to detect repository configuration",
425	            cause: error,
426	          });
427	        }
428	      }),
429	  },
430	
431	  /**
432	   * Vercel-specific operations
433	   */
434	  vercel: {
435	    /**
436	     * Disconnect Vercel integration.
437	     *
438	     * Delegates to the memory service which triggers the durable
439	     * connection-teardown workflow (gate-first: closes ingress immediately).
440	     */
441	    disconnect: orgScopedProcedure.mutation(async ({ ctx }) => {
442	      // Fetch Vercel installation to get id; enforce org scoping
443	      const rows = await ctx.db
444	        .select({ id: gatewayInstallations.id })
445	        .from(gatewayInstallations)
446	        .where(
447	          and(
448	            eq(gatewayInstallations.orgId, ctx.auth.orgId),
449	            eq(gatewayInstallations.provider, "vercel")
450	          )
451	        )
452	        .limit(1);
453	
454	      const installation = rows[0];
455	      if (!installation) {
456	        throw new TRPCError({
457	          code: "NOT_FOUND",
458	          message: "Vercel integration not found",
459	        });
460	      }
461	
462	      const platform = await createPlatformCaller();
463	      await platform.connections.disconnect({
464	        id: installation.id,
465	        provider: "vercel",
466	      });
467	
468	      // Cascade: mark all org integrations for this installation as disconnected
469	      const now = new Date().toISOString();
470	      await ctx.db
471	        .update(orgIntegrations)
472	        .set({
473	          status: "disconnected",
474	          statusReason: "installation_revoked",
475	          updatedAt: now,
476	        })
477	        .where(eq(orgIntegrations.installationId, installation.id));
478	
479	      return { success: true };
480	    }),
481	  },
482	
483	  // ── Generic Resource Picker Procedures ────────────────────────────────────
484	
485	  // ── Linked Resources (orgIntegrations) ────────────────────────────────────
486	
487	  resources: {
488	    /**
489	     * List linked resources for the current org.
490	     *
491	     * Joins orgIntegrations with gatewayInstallations to return
492	     * per-resource metadata including backfill config.
493	     */
494	    list: orgScopedProcedure.query(async ({ ctx }) => {
495	      const rows = await ctx.db
496	        .select({
497	          id: orgIntegrations.id,
498	          provider: orgIntegrations.provider,
499	          providerConfig: orgIntegrations.providerConfig,
500	          providerResourceId: orgIntegrations.providerResourceId,
501	          installationId: orgIntegrations.installationId,
502	          documentCount: orgIntegrations.documentCount,
503	          backfillConfig: gatewayInstallations.backfillConfig,
504	        })
505	        .from(orgIntegrations)
506	        .leftJoin(
507	          gatewayInstallations,
508	          eq(orgIntegrations.installationId, gatewayInstallations.id)
509	        )
510	        .where(
511	          and(
512	            eq(orgIntegrations.clerkOrgId, ctx.auth.orgId),
513	            eq(orgIntegrations.status, "active")
514	          )
515	        );
516	
517	      const list = rows.map((row) => {
518	        // ProviderConfig is a discriminated union — access common fields via cast
519	        const config = row.providerConfig as {
520	          sync?: { events?: string[] };
521	          status?: { configStatus?: string };
522	        };
523	        return {
524	          id: row.id,
525	          metadata: {
526	            provider: row.provider,
527	            sync: config.sync
528	              ? { events: config.sync.events ?? [] }
529	              : undefined,
530	            status: config.status
531	              ? { configStatus: config.status.configStatus }
532	              : undefined,
533	          },
534	          displayName: row.providerResourceId,
535	          installationId: row.installationId,
536	          documentCount: row.documentCount,
537	          backfillConfig: row.backfillConfig,
538	        };
539	      });
540	
541	      return { list };
542	    }),
543	
544	    /**
545	     * Bulk-link resources from a gateway installation to this org.
546	     *
547	     * Creates new orgIntegration rows, or reactivates disconnected ones.
548	     * Returns counts of created / reactivated entries.
549	     */
550	    bulkLink: orgScopedProcedure
551	      .input(
552	        z.object({
553	          provider: sourceTypeSchema,
554	          gwInstallationId: z.string().min(1),
555	          resources: z
556	            .array(
557	              z.object({
558	                resourceId: z.string(),
559	                resourceName: z.string().optional(),
560	              })
561	            )
562	            .min(1),
563	        })
564	      )
565	      .mutation(async ({ ctx, input }) => {
566	        // Verify the installation belongs to this org
567	        const installation = await ctx.db
568	          .select({ id: gatewayInstallations.id })
569	          .from(gatewayInstallations)
570	          .where(
571	            and(
572	              eq(gatewayInstallations.id, input.gwInstallationId),
573	              eq(gatewayInstallations.orgId, ctx.auth.orgId),
574	              eq(gatewayInstallations.status, "active")
575	            )
576	          )
577	          .limit(1)
578	          .then((rows) => rows[0]);
579	
580	        if (!installation) {
581	          throw new TRPCError({
582	            code: "NOT_FOUND",
583	            message: "Installation not found or not owned by this org",
584	          });
585	        }
586	
587	        const providerDef = getProvider(input.provider);
588	        if (!providerDef) {
589	          throw new TRPCError({
590	            code: "BAD_REQUEST",
591	            message: `Unknown provider: ${input.provider}`,
592	          });
593	        }
594	
595	        const defaultSyncEvents = getDefaultSyncEvents(
596	          input.provider as ProviderName
597	        );
598	        const providerConfig = providerDef.buildProviderConfig({
599	          defaultSyncEvents: [...defaultSyncEvents],
600	        });
601	
602	        let created = 0;
603	        let reactivated = 0;
604	
605	        for (const resource of input.resources) {
606	          const existing = await ctx.db
607	            .select({ id: orgIntegrations.id })
608	            .from(orgIntegrations)
609	            .where(
610	              and(
611	                eq(orgIntegrations.installationId, input.gwInstallationId),
612	                eq(
613	                  orgIntegrations.providerResourceId,
614	                  resource.resourceId as SourceIdentifier
615	                )
616	              )
617	            )
618	            .then((rows) => rows[0]);
619	
620	          await ctx.db
621	            .insert(orgIntegrations)
622	            .values({
623	              clerkOrgId: ctx.auth.orgId,
624	              installationId: input.gwInstallationId,
625	              provider: input.provider,
626	              providerConfig,
627	              providerResourceId: resource.resourceId as SourceIdentifier,
628	            })
629	            .onConflictDoUpdate({
630	              target: [
631	                orgIntegrations.installationId,
632	                orgIntegrations.providerResourceId,
633	              ],
634	              set: {
635	                status: "active",
636	                statusReason: null,
637	                updatedAt: new Date().toISOString(),
638	              },
639	            });
640	
641	          if (existing) {
642	            reactivated++;
643	          } else {
644	            created++;
645	          }
646	        }
647	
648	        return { created, reactivated };
649	      }),
650	  },
651	
652	  generic: {
653	    listInstallations: orgScopedProcedure
654	      .input(z.object({ provider: sourceTypeSchema }))
655	      .query(async ({ ctx, input }) => {
656	        const providerDef = getProvider(input.provider);
657	        if (!providerDef) {
658	          throw new TRPCError({
659	            code: "BAD_REQUEST",
660	            message: `Unknown provider: ${input.provider}`,
661	          });
662	        }
663	
664	        const installations = await ctx.db
665	          .select()
666	          .from(gatewayInstallations)
667	          .where(
668	            and(
669	              eq(gatewayInstallations.orgId, ctx.auth.orgId),
670	              eq(gatewayInstallations.provider, input.provider),
671	              eq(gatewayInstallations.status, "active")
672	            )
673	          );
674	
675	        if (installations.length === 0) {
676	          return {
677	            installationMode: providerDef.resourcePicker.installationMode,
678	            resourceLabel: providerDef.resourcePicker.resourceLabel,
679	            installations: [] as NormalizedInstallation[],
680	          };
681	        }
682	
683	        const platform = await createPlatformCaller();
684	
685	        const enriched = await Promise.all(
686	          installations.map(async (inst) => {
687	            const executeApi: ResourcePickerExecuteApiFn = (request) =>
688	              platform.proxy.execute({
689	                installationId: inst.id,
690	                ...request,
691	              });
692	
693	            return providerDef.resourcePicker.enrichInstallation(executeApi, {
694	              id: inst.id,
695	              externalId: inst.externalId,
696	              // ProviderDefinition loses TAccountInfo generic — contravariance on
697	              // ResourcePickerDef method params collapses the union to never | null.
698	              // Runtime value is always the correct type for this provider.
699	              providerAccountInfo: inst.providerAccountInfo as any,
700	            });
701	          })
702	        );
703	
704	        return {
705	          installationMode: providerDef.resourcePicker.installationMode,
706	          resourceLabel: providerDef.resourcePicker.resourceLabel,
707	          installations: enriched,
708	        };
709	      }),
710	
711	    listResources: orgScopedProcedure
712	      .input(
713	        z.object({
714	          provider: sourceTypeSchema,
715	          installationId: z.string(),
716	        })
717	      )
718	      .query(async ({ ctx, input }) => {
719	        const providerDef = getProvider(input.provider);
720	        if (!providerDef) {
721	          throw new TRPCError({
722	            code: "BAD_REQUEST",
723	            message: `Unknown provider: ${input.provider}`,
724	          });
725	        }
726	
727	        // Verify org owns this installation
728	        const installation = await ctx.db
729	          .select()
730	          .from(gatewayInstallations)
731	          .where(
732	            and(
733	              eq(gatewayInstallations.id, input.installationId),
734	              eq(gatewayInstallations.orgId, ctx.auth.orgId),
735	              eq(gatewayInstallations.provider, input.provider),
736	              eq(gatewayInstallations.status, "active")
737	            )
738	          )
739	          .limit(1)
740	          .then((rows) => rows[0]);
741	
742	        if (!installation) {
743	          throw new TRPCError({
744	            code: "NOT_FOUND",
745	            message: "Installation not found or not owned by this org",
746	          });
747	        }
748	
749	        const platform = await createPlatformCaller();
750	
751	        const executeApi: ResourcePickerExecuteApiFn = async (request) => {
752	          const result = await platform.proxy.execute({
753	            installationId: installation.id,
754	            ...request,
755	          });
756	          if (result.status === 401) {
757	            await ctx.db
758	              .update(gatewayInstallations)
759	              .set({ status: "error" })
760	              .where(eq(gatewayInstallations.id, installation.id));
761	            throw new TRPCError({
762	              code: "UNAUTHORIZED",
763	              message: "Provider connection expired. Please reconnect.",
764	            });
765	          }
766	          return result;
767	        };
768	
769	        const resources = await providerDef.resourcePicker.listResources(
770	          executeApi,
771	          {
772	            id: installation.id,
773	            externalId: installation.externalId,
774	            // ProviderDefinition loses TAccountInfo generic — see comment above.
775	            providerAccountInfo: installation.providerAccountInfo as any,
776	          }
777	        );
778	
779	        return { resources };
780	      }),
781	  },
782	} satisfies TRPCRouterRecord;
