/**
 * Connections tRPC sub-router.
 *
 * All procedures use serviceProcedure (JWT auth required).
 * orgId comes as an input parameter (no tenant middleware in tRPC).
 *
 * `disconnect` fires the "platform/connection.lifecycle" Inngest event
 * to trigger the connection teardown workflow.
 */
import { db } from "@db/app/client";
import {
  gatewayBackfillRuns,
  gatewayInstallations,
  gatewayLifecycleLogs,
} from "@db/app/schema";
import type { ProviderDefinition } from "@repo/app-providers";
import { getProvider, sourceTypeSchema } from "@repo/app-providers";
import {
  BACKFILL_TERMINAL_STATUSES,
  backfillRunRecord,
} from "@repo/app-providers/contracts";
import type { TRPCRouterRecord } from "@trpc/server";
import { TRPCError } from "@trpc/server";
import { and, eq } from "@vendor/db";
import { log } from "@vendor/observability/log/next";
import { z } from "zod";
import { inngest } from "../../inngest/client";
import { buildAuthorizeUrl } from "../../lib/oauth/authorize";
import { providerConfigs } from "../../lib/provider-configs";
import { getActiveTokenForInstallation } from "../../lib/token-helpers";
import { serviceProcedure } from "../../trpc";

// ── Connections Router ──────────────────────────────────────────────────────

export const connectionsRouter = {
  /**
   * List installations, optionally filtered by status.
   * Source: GET /connections
   */
  list: serviceProcedure
    .input(
      z.object({
        orgId: z.string(),
        status: z.string().optional(),
      })
    )
    .query(async ({ input }) => {
      const conditions = [eq(gatewayInstallations.orgId, input.orgId)];
      if (input.status) {
        conditions.push(eq(gatewayInstallations.status, input.status));
      }

      const rows = await db
        .select({
          id: gatewayInstallations.id,
          provider: gatewayInstallations.provider,
          externalId: gatewayInstallations.externalId,
          orgId: gatewayInstallations.orgId,
          status: gatewayInstallations.status,
        })
        .from(gatewayInstallations)
        .where(and(...conditions));

      return rows;
    }),

  /**
   * Token vault -- returns decrypted provider token for a connection.
   * Source: GET /connections/:id/token
   */
  getToken: serviceProcedure
    .input(
      z.object({
        id: z.string(),
      })
    )
    .query(async ({ input }) => {
      const installationRows = await db
        .select()
        .from(gatewayInstallations)
        .where(eq(gatewayInstallations.id, input.id))
        .limit(1);

      const installation = installationRows[0];

      if (!installation) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "Connection not found",
        });
      }

      if (installation.status !== "active") {
        throw new TRPCError({
          code: "BAD_REQUEST",
          message: `Installation not active (status: ${installation.status})`,
        });
      }

      const providerName = installation.provider;
      const config = providerConfigs[providerName];

      try {
        const providerDef = getProvider(providerName);

        // SAFETY: getProvider() returns the full generic ProviderDefinition<TConfig, ...>
        // but the helper takes the base ProviderDefinition. The generic parameters are
        // erased at runtime -- the cast is safe because the concrete type is a supertype.
        const { token, expiresAt } = await getActiveTokenForInstallation(
          installation,
          config,
          providerDef as ProviderDefinition
        );

        return {
          accessToken: token,
          provider: providerName,
          expiresIn: expiresAt
            ? Math.floor((new Date(expiresAt).getTime() - Date.now()) / 1000)
            : 3600, // GitHub installation tokens expire in 1 hour
        };
      } catch (err) {
        const message = err instanceof Error ? err.message : "unknown";
        log.warn("[connections] token retrieval failed", {
          installationId: input.id,
          provider: providerName,
          error: message,
        });

        if (message === "no_token_found") {
          throw new TRPCError({
            code: "NOT_FOUND",
            message: "no_token_found",
          });
        }
        if (
          message === "token_expired" ||
          message === "token_expired:no_refresh_token"
        ) {
          throw new TRPCError({
            code: "BAD_REQUEST",
            message,
          });
        }
        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: `token_generation_failed: ${message}`,
        });
      }
    }),

  /**
   * Disconnect (teardown) a connection.
   *
   * Fires "platform/connection.lifecycle" Inngest event to initiate teardown.
   */
  disconnect: serviceProcedure
    .input(
      z.object({
        id: z.string(),
        provider: sourceTypeSchema,
      })
    )
    .mutation(async ({ input }) => {
      const installationRows = await db
        .select()
        .from(gatewayInstallations)
        .where(
          and(
            eq(gatewayInstallations.id, input.id),
            eq(gatewayInstallations.provider, input.provider)
          )
        )
        .limit(1);

      const installation = installationRows[0];

      if (!installation) {
        throw new TRPCError({
          code: "NOT_FOUND",
          message: "Connection not found",
        });
      }

      // Audit log: capture user-initiated disconnect intent before event fires
      await db.insert(gatewayLifecycleLogs).values({
        installationId: input.id,
        event: "user_disconnect",
        fromStatus: installation.status,
        toStatus: "revoked",
        reason: "User-initiated disconnect via platform service",
        metadata: {
          source: "platform_disconnect_handler",
          triggeredBy: "user",
        },
      });

      // Fire Inngest event to trigger connection teardown workflow
      await inngest.send({
        name: "platform/connection.lifecycle",
        data: {
          reason: "user_disconnect",
          installationId: input.id,
          orgId: installation.orgId,
          provider: input.provider,
          triggeredBy: "user" as const,
        },
      });

      return { status: "teardown_initiated", installationId: input.id };
    }),

  /**
   * Build OAuth authorize URL for a provider.
   * Source: GET /connections/:provider/authorize
   */
  getAuthorizeUrl: serviceProcedure
    .input(
      z.object({
        provider: sourceTypeSchema,
        orgId: z.string(),
        connectedBy: z.string(),
        redirectTo: z.string().optional(),
      })
    )
    .query(async ({ input }) => {
      const result = await buildAuthorizeUrl({
        provider: input.provider,
        orgId: input.orgId,
        connectedBy: input.connectedBy,
        redirectTo: input.redirectTo,
      });

      if (!result.ok) {
        throw new TRPCError({
          code: "BAD_REQUEST",
          message: result.error,
        });
      }

      return { url: result.url, state: result.state };
    }),

  /**
   * List backfill runs for a connection.
   * Source: GET /connections/:id/backfill-runs
   */
  listBackfillRuns: serviceProcedure
    .input(
      z.object({
        installationId: z.string(),
        status: z.string().optional(),
      })
    )
    .query(async ({ input }) => {
      const conditions = [
        eq(gatewayBackfillRuns.installationId, input.installationId),
      ];
      if (input.status) {
        conditions.push(eq(gatewayBackfillRuns.status, input.status));
      }

      const runs = await db
        .select({
          entityType: gatewayBackfillRuns.entityType,
          providerResourceId: gatewayBackfillRuns.providerResourceId,
          since: gatewayBackfillRuns.since,
          depth: gatewayBackfillRuns.depth,
          status: gatewayBackfillRuns.status,
          pagesProcessed: gatewayBackfillRuns.pagesProcessed,
          eventsProduced: gatewayBackfillRuns.eventsProduced,
          eventsDispatched: gatewayBackfillRuns.eventsDispatched,
          completedAt: gatewayBackfillRuns.completedAt,
        })
        .from(gatewayBackfillRuns)
        .where(and(...conditions));

      return runs;
    }),

  /**
   * Upsert a backfill run record.
   * Source: POST /connections/:id/backfill-runs
   */
  upsertBackfillRun: serviceProcedure
    .input(
      z.object({
        installationId: z.string(),
        run: backfillRunRecord,
      })
    )
    .mutation(async ({ input }) => {
      const now = new Date().toISOString();
      const data = input.run;
      const isTerminal = (
        BACKFILL_TERMINAL_STATUSES as readonly string[]
      ).includes(data.status);

      const sharedFields = {
        since: data.since,
        depth: data.depth,
        status: data.status,
        pagesProcessed: data.pagesProcessed,
        eventsProduced: data.eventsProduced,
        eventsDispatched: data.eventsDispatched,
        error: data.error ?? null,
        completedAt: isTerminal ? now : null,
        updatedAt: now,
      };

      await db
        .insert(gatewayBackfillRuns)
        .values({
          installationId: input.installationId,
          entityType: data.entityType,
          providerResourceId: data.providerResourceId,
          ...sharedFields,
          startedAt: data.status === "running" ? now : null,
        })
        .onConflictDoUpdate({
          target: [
            gatewayBackfillRuns.installationId,
            gatewayBackfillRuns.providerResourceId,
            gatewayBackfillRuns.entityType,
          ],
          set: sharedFields,
        });

      return { status: "ok" as const };
    }),
} satisfies TRPCRouterRecord;

import { clerkOrgSlugSchema } from "@repo/app-validation";
import type { TRPCRouterRecord } from "@trpc/server";
import { TRPCError } from "@trpc/server";
import { clerkClient } from "@vendor/clerk/server";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { z } from "zod";

import { userScopedProcedure, verifyOrgMembership } from "../../trpc";

/**
 * Organization router - Clerk-based organization management
 *
 * Phase 1.6: Organizations are managed entirely in Clerk (source of truth)
 * No database table for organizations - Clerk handles all org data
 */
export const organizationRouter = {
  /**
   * List user's organizations from Clerk
   *
   * Returns all organizations the authenticated user belongs to.
   * Used by org-switcher component in the header.
   */
  listUserOrganizations: userScopedProcedure.query(async ({ ctx }) => {
    // userScopedProcedure guarantees clerk-pending or clerk-active
    const userId = ctx.auth.userId;
    const clerk = await clerkClient();

    // Get all organizations the user belongs to from Clerk
    const { data: memberships } =
      await clerk.users.getOrganizationMembershipList({
        userId,
      });

    // Return Clerk organization data directly
    return memberships.map((membership) => {
      const clerkOrg = membership.organization;

      return {
        id: clerkOrg.id, // Clerk org ID
        slug: clerkOrg.slug,
        name: clerkOrg.name,
        role: membership.role,
        imageUrl: clerkOrg.imageUrl,
      };
    });
  }),

  /**
   * Create organization
   * Creates a new Clerk organization with the user as admin
   *
   * Used by team creation flow at /account/teams/new
   * Does NOT create a default project - user sets up integrations separately
   */
  create: userScopedProcedure
    .input(
      z.object({
        slug: clerkOrgSlugSchema,
      })
    )
    .mutation(async ({ ctx, input }) => {
      // userScopedProcedure guarantees clerk-pending or clerk-active
      log.info("[organization] create", {
        slug: input.slug,
        userId: ctx.auth.userId,
        authType: ctx.auth.type,
      });

      const clerk = await clerkClient();

      try {
        // Create Clerk organization (slug used for both name and slug)
        const clerkOrg = await clerk.organizations.createOrganization({
          name: input.slug,
          slug: input.slug,
          createdBy: ctx.auth.userId,
        });

        log.info("[organization] create success", {
          organizationId: clerkOrg.id,
          slug: clerkOrg.slug,
        });

        return {
          organizationId: clerkOrg.id,
          slug: clerkOrg.slug || input.slug,
        };
      } catch (error: unknown) {
        log.error("[organization] create failed", {
          slug: input.slug,
          userId: ctx.auth.userId,
          error: parseError(error),
          errorDetails: error,
        });

        // Check for specific Clerk errors
        if (error && typeof error === "object" && "errors" in error) {
          const clerkError = error as {
            errors?: { code: string; message: string }[];
          };

          log.error("[organization] clerk error details", {
            errors: clerkError.errors,
          });

          if (
            clerkError.errors?.[0]?.code === "duplicate_record" ||
            clerkError.errors?.[0]?.code === "form_identifier_exists" ||
            clerkError.errors?.[0]?.message.includes("already exists") ||
            clerkError.errors?.[0]?.message.includes("slug is taken")
          ) {
            throw new TRPCError({
              code: "CONFLICT",
              message: `An organization with the name "${input.slug}" already exists`,
            });
          }
        }

        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to create organization",
          cause: error,
        });
      }
    }),

  /**
   * Update organization name
   * Used by team settings page to update the organization name/slug in Clerk
   *
   * Only organization admins can update the organization name
   */
  updateName: userScopedProcedure
    .input(
      z.object({
        slug: z.string().min(1, "Organization slug is required"),
        name: clerkOrgSlugSchema,
      })
    )
    .mutation(async ({ ctx, input }) => {
      // userScopedProcedure guarantees clerk-pending or clerk-active
      const clerk = await clerkClient();

      try {
        // Get organization by slug
        const org = await clerk.organizations.getOrganization({
          slug: input.slug,
        });

        // Verify user has admin access to the organization
        await verifyOrgMembership({
          clerkOrgId: org.id,
          userId: ctx.auth.userId,
          requireAdmin: true,
        });

        // Update organization in Clerk
        await clerk.organizations.updateOrganization(org.id, {
          name: input.name,
          slug: input.name, // Clerk uses slug for URL-safe names
        });

        log.info("[organization] updateName success", {
          organizationId: org.id,
          slug: input.name,
          userId: ctx.auth.userId,
        });

        return {
          success: true,
          id: org.id, // Return org ID for setActive calls
          name: input.name,
        };
      } catch (error: unknown) {
        // Re-throw TRPCError as-is
        if (error instanceof TRPCError) {
          throw error;
        }

        log.error("[organization] updateName failed", {
          slug: input.slug,
          userId: ctx.auth.userId,
          error: parseError(error),
        });

        // Check for specific Clerk errors
        if (error && typeof error === "object" && "errors" in error) {
          const clerkError = error as {
            errors?: { code: string; message: string }[];
          };

          if (
            clerkError.errors?.[0]?.code === "duplicate_record" ||
            clerkError.errors?.[0]?.code === "form_identifier_exists" ||
            clerkError.errors?.[0]?.message.includes("already exists") ||
            clerkError.errors?.[0]?.message.includes("slug is taken")
          ) {
            throw new TRPCError({
              code: "CONFLICT",
              message: `An organization with the name "${input.name}" already exists`,
            });
          }
        }

        throw new TRPCError({
          code: "INTERNAL_SERVER_ERROR",
          message: "Failed to update organization",
          cause: error,
        });
      }
    }),
} satisfies TRPCRouterRecord;

