#### 4.2 New procedure: `organization.createFromPendingInstall`

**File**: `api/app/src/router/user/organization.ts`

```ts
import { gatewayInstallations, pendingInstallations } from "@db/app/schema";
import { db } from "@db/app/client";
import { and, eq } from "drizzle-orm";

createFromPendingInstall: userScopedProcedure
  .input(z.object({ pendingInstallId: z.string() }))
  .mutation(async ({ ctx, input }) => {
    // 1. Read pending install
    const [pending] = await db
      .select()
      .from(pendingInstallations)
      .where(
        and(
          eq(pendingInstallations.id, input.pendingInstallId),
          eq(pendingInstallations.connectedBy, ctx.auth.userId)
        )
      )
      .limit(1);

    if (!pending) {
      throw new TRPCError({ code: "NOT_FOUND", message: "Pending install not found" });
    }

    // 2. Re-check 1:1 constraint (belt-and-suspenders)
    const existingBinding = await db
      .select({ id: gatewayInstallations.id })
      .from(gatewayInstallations)
      .where(
        and(
          eq(gatewayInstallations.provider, pending.provider),
          eq(gatewayInstallations.providerOrgId, pending.providerOrgId)
        )
      )
      .limit(1);

    if (existingBinding.length > 0) {
      throw new TRPCError({
        code: "CONFLICT",
        message: "This GitHub organization is already connected to a workspace",
      });
    }

    // 3. Normalize slug (GitHub logins are [a-z0-9-] but validate defensively)
    const slug = pending.providerOrgLogin.toLowerCase().replace(/[^a-z0-9-]/g, "");
    if (!slug) {
      throw new TRPCError({ code: "BAD_REQUEST", message: "GitHub org login produced an invalid slug" });
    }

    // 4. Create Clerk org
    const clerk = await clerkClient();
    const clerkOrg = await clerk.organizations.createOrganization({
      name: pending.providerOrgLogin,
      slug,
      createdBy: ctx.auth.userId,
    });

    // 5. Create gatewayInstallations row — if this fails, clean up the Clerk org
    try {
      await db.insert(gatewayInstallations).values({
        provider: pending.provider,
        externalId: pending.externalId,
        connectedBy: pending.connectedBy,
        orgId: clerkOrg.id,
        status: "active",
        providerAccountInfo: pending.providerAccountInfo,
        providerOrgId: pending.providerOrgId,
        providerOrgLogin: pending.providerOrgLogin,
      });
    } catch (insertError) {
      // Unique constraint on (provider, providerOrgId) — another user claimed this org
      log.error("[organization] gatewayInstallation insert failed, deleting orphaned Clerk org", {
        clerkOrgId: clerkOrg.id,
        error: parseError(insertError),
      });
      await clerk.organizations.deleteOrganization(clerkOrg.id);
      throw new TRPCError({
        code: "CONFLICT",
        message: "This GitHub organization was just connected to another workspace",
      });
    }

    // 6. Delete pending install
    await db
      .delete(pendingInstallations)
      .where(eq(pendingInstallations.id, pending.id));

    log.info("[organization] created from GitHub install", {
      clerkOrgId: clerkOrg.id,
      slug: clerkOrg.slug,
      providerOrgId: pending.providerOrgId,
    });

    return {
      organizationId: clerkOrg.id,
      slug: clerkOrg.slug ?? slug,
    };
  }),
```

Clerk error handling for slug conflicts follows the same pattern as the existing `organization.create` procedure — catch Clerk errors, throw `TRPCError({ code: "CONFLICT" })`. The gatewayInstallation insert is wrapped in try/catch to clean up the Clerk org if the unique constraint on `(provider, providerOrgId)` fires (prevents orphaned Clerk orgs in a race condition).

