```ts
import type { SourceType } from "@repo/app-providers";
import type { ProviderAccountInfo } from "@repo/app-providers";
import type { ClerkUserId } from "@repo/app-validation";
import { nanoid } from "@repo/lib";
import {
  index,
  jsonb,
  pgTable,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";

export const pendingInstallations = pgTable(
  "lightfast_pending_installations",
  {
    id: varchar("id", { length: 191 })
      .notNull()
      .primaryKey()
      .$defaultFn(() => nanoid()),

    provider: varchar("provider", { length: 50 }).notNull().$type<SourceType>(),
    externalId: varchar("external_id", { length: 191 }).notNull(),

    providerOrgId: varchar("provider_org_id", { length: 191 }).notNull(),
    providerOrgLogin: varchar("provider_org_login", { length: 191 }).notNull(),
    providerOrgAvatarUrl: varchar("provider_org_avatar_url", { length: 500 }),

    connectedBy: varchar("connected_by", { length: 191 })
      .notNull()
      .$type<ClerkUserId>(),

    providerAccountInfo: jsonb("provider_account_info").$type<ProviderAccountInfo>(),

    createdAt: timestamp("created_at", { mode: "string", withTimezone: true })
      .notNull()
      .defaultNow(),
  },
  (table) => ({
    providerExternalIdx: uniqueIndex("pending_inst_provider_external_idx").on(
      table.provider,
      table.externalId
    ),
    connectedByIdx: index("pending_inst_connected_by_idx").on(
      table.connectedBy
    ),
  })
);

export type PendingInstallation = typeof pendingInstallations.$inferSelect;
export type InsertPendingInstallation = typeof pendingInstallations.$inferInsert;
```

